// CSD_RATIONALE_BEGIN
// I chose TryUnconstrainedThenConstrained because FOL expressions often require a bit of creative freedom early,
// but we still need to ensure the generated prefix remains valid under a strict parser. 
// N=5 is small enough to avoid wasting resources if the parser is very strict, while allowing some flexibility.
// CSD_RATIONALE_END
if maxSteps < 5 {
  generated := CSDHelpers.PureConstrainedGeneration(lm, parser, prompt, maxSteps);
} else {
  generated := CSDHelpers.TryUnconstrainedThenConstrained(lm, parser, prompt, maxSteps, 5);
}
